public static ArrayList<Integer> bucketsort(ArrayList<Integer> arr, int k) {
    // Create a new ArrayList with size k to store the counts
    ArrayList<Integer> counts = new ArrayList<>(k);
    for (int i = 0; i < k; i++) {
        counts.add(0);
    }
    // Loop through the input array and increment the counts
    for (Integer x : arr) {
        counts.set(x, counts.get(x) + 1);
    }
    // Create a new ArrayList with size arr.size() to store the sorted elements
    ArrayList<Integer> sortedArr = new ArrayList<>(arr.size());
    // Loop through the counts and add the elements from the input array to the sorted array
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < counts.get(i); j++) {
            sortedArr.add(i);
        }
    }
    return sortedArr;
}

